import{_ as e,o as s,c as n,a2 as i}from"./chunks/framework.BFVZdVmd.js";const g=JSON.parse('{"title":"日志体系（ELK / Loki）","description":"","frontmatter":{},"headers":[],"relativePath":"observability/logging.md","filePath":"observability/logging.md","lastUpdated":null}'),l={name:"observability/logging.md"};function t(o,a,c,d,p,r){return s(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="日志体系-elk-loki" tabindex="-1">日志体系（ELK / Loki） <a class="header-anchor" href="#日志体系-elk-loki" aria-label="Permalink to &quot;日志体系（ELK / Loki）&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><ul><li><code>Logback</code>：Spring Boot 默认日志框架。</li><li><code>Log4j2</code>：高性能日志框架。</li><li><code>SLF4J</code>：日志门面（统一日志 API）。</li><li><code>ELK</code>：Elasticsearch + Logstash + Kibana，日志采集、存储、检索、分析。</li><li><code>EFK</code>：Elasticsearch + Fluentd + Kibana。</li><li><code>Loki</code>：Grafana 生态的轻量日志系统，成本低。</li><li><code>Fluent Bit</code> / <code>Filebeat</code>：日志采集 Agent。</li></ul><h2 id="解决什么问题" tabindex="-1">解决什么问题 <a class="header-anchor" href="#解决什么问题" aria-label="Permalink to &quot;解决什么问题&quot;">​</a></h2><p>微服务分散在多台机器、多个容器，日志散落各处。集中式日志平台把所有服务的日志收集到一起，支持统一检索、过滤、告警，排查问题不用再逐台登录看文件。</p><h2 id="企业日志需要关注的字段" tabindex="-1">企业日志需要关注的字段 <a class="header-anchor" href="#企业日志需要关注的字段" aria-label="Permalink to &quot;企业日志需要关注的字段&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>traceId</span></span>
<span class="line"><span>用户 ID</span></span>
<span class="line"><span>请求路径</span></span>
<span class="line"><span>请求耗时</span></span>
<span class="line"><span>异常堆栈</span></span>
<span class="line"><span>服务名</span></span>
<span class="line"><span>环境标识</span></span>
<span class="line"><span>机器 IP</span></span></code></pre></div><h2 id="全链路日志" tabindex="-1">全链路日志 <a class="header-anchor" href="#全链路日志" aria-label="Permalink to &quot;全链路日志&quot;">​</a></h2><p>微服务项目最好统一接入 <strong>traceId 全链路日志</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一个请求 -&gt; 生成 traceId -&gt; 贯穿所有服务的日志 -&gt; 按 traceId 聚合查看</span></span></code></pre></div><p>否则跨服务排查问题会非常困难。<code>traceId</code> 要和<a href="./skywalking">链路追踪</a>打通。</p><h2 id="选型建议" tabindex="-1">选型建议 <a class="header-anchor" href="#选型建议" aria-label="Permalink to &quot;选型建议&quot;">​</a></h2><ul><li>已经用了 Elasticsearch 的项目，日志直接走 <code>ELK / EFK</code> 比较自然。</li><li>想降低存储成本、已用 Grafana 的项目，推荐 <code>Loki</code>。</li><li>采集端用 <code>Filebeat</code> 或 <code>Fluent Bit</code> 都可以，轻量优先 Fluent Bit。</li></ul>`,13)])])}const u=e(l,[["render",t]]);export{g as __pageData,u as default};
